mapper.select:
SELECT id, title, content, notice_type as noticeType, status, sort, create_by as createBy, update_by as updateBy, create_time as createTime, update_time as updateTime from admin_notice
is_deleted = 0
and title like concat('%', #{query.title}, '%')
and notice_type = #{query.noticeType}
and status = #{query.status}
and create_time >= #{query.startTime}
and create_time <= #{query.endTime}
order by sort asc, create_time desc, id desc
